output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?place ?placeLabel ?population WHERE {
  {
    ?place wdt:P131 ?county ; wdt:P31 wd:Q515 ; wdt:P1082 ?population .
    ?county wdt:P131 wd:Q1371
  } UNION {
    ?place wdt:P131 ?county ; wdt:P31 wd:Q486972 ; wdt:P1082 ?population .
    ?county wdt:P131 wd:Q1371
  }
  ?place rdfs:label ?placeLabel .
  FILTER(LANG(?placeLabel) = 'en')
}
ORDER BY DESC(?population)
LIMIT 1

